import json,re,statistics
files={'bodhi':'bodhi.jsonl','lunon':'lunon.jsonl','whale':'WhaleCloud-DocChain_0612.jsonl','cellcog':'cellcog-max.jsonl','dalpha':'dalpha-deepresearch.jsonl','sourcery':'sourcery.jsonl','gemini':'gemini-2.5-pro-deepresearch.jsonl'}
KEY='literature review on the restructuring impact'
arts={}
for k,f in files.items():
    for line in open(f):
        d=json.loads(line)
        if KEY in d.get('prompt',''): arts[k]=d['article']

# crude finite-verb detector: a heading is "claim-first" if it contains a finite verb form
FIN = re.compile(r'\b(is|are|was|were|has|have|had|does|do|did|can|could|may|might|must|will|would|should|remains?|depends?|predicts?|shows?|reveals?|suggests?|drives?|explains?|reshapes?|fails?|persists?|varies|varies|differs?|matters?|holds?|falls?|rises?|creates?|destroys?|hides?|masks?|outpaces?|lags?|converges?|diverges?|reconciles?|situates?|is not|isn\'t|do not|does not|cannot)\b', re.I)
for k,a in arts.items():
    hs=[l.strip().lstrip('#').strip() for l in a.split('\n') if re.match(r'^###\s+\S',l.strip()) and not l.strip().startswith('####')]
    if not hs: 
        print(f"{k:9s} H3=0"); continue
    fin=[h for h in hs if FIN.search(re.sub(r'^[\d.]+\s*','',h))]
    print(f"{k:9s} H3={len(hs):3d}  with-finite-verb={len(fin):3d}  ({100*len(fin)/len(hs):.0f}%)")
    for h in fin[:5]: print("      CLAIMY:",h[:95])
    # numbered?
    num=sum(1 for h in hs if re.match(r'^\d+\.\d+',h))
    print(f"      numbered={num}/{len(hs)}")
EOF

